WITH payload AS (
  SELECT $RISQQ111${"questions":[{"section_code":"08F","section_number":8,"section_letter":"F","section_title":"Cargo Operation - Heavy lift vessel","printed_question_no":"8.8","internal_question_no":"08F.008","question_sort_key":8600800.363,"question_text":"Is there a qualified individual responsible for ballast control and stability calculations?","guide_to_inspection":"If the vessel is classified as a Mobile Offshore Unit (MoU), the ballast control operator must comply with the competency\nrequirements outlined in Table 6.4 of IMO Resolution 891. For vessels that do not fall under the MoU category, RightShip\nrecommends that the vessel’s manager arrange specific training for the individual responsible for ballast control operations to\nensure safe and effective practices.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":167,"source_page_end":167,"raw_source_text":"Is there a qualified individual responsible for ballast control and stability calculations? (V)\nGuide to Inspection\nIf the vessel is classified as a Mobile Offshore Unit (MoU), the ballast control operator must comply with the competency\nrequirements outlined in Table 6.4 of IMO Resolution 891. For vessels that do not fall under the MoU category, RightShip\nrecommends that the vessel’s manager arrange specific training for the individual responsible for ballast control operations to\nensure safe and effective practices.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08F","section_number":8,"section_letter":"F","section_title":"Cargo Operation - Heavy lift vessel","printed_question_no":"8.9","internal_question_no":"08F.009","question_sort_key":8600900.364,"question_text":"Do the training records of the Ballast Control Operators (BCOs) show their understanding of the vessel ballast system, the management of free surface effects, and the implications of unintentional ballast shifts?","guide_to_inspection":"The inspector needs to examine the records for induction and vessel-specific training. If the heavy lift vessel is semi-\nsubmersible, the BCO should be capable of taking the unit to survival draft if necessary.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":167,"source_page_end":167,"raw_source_text":"Do the training records of the Ballast Control Operators (BCOs) show their understanding of the vessel ballast\nsystem, the management of free surface effects, and the implications of unintentional ballast shifts? (V)\nGuide to Inspection\nThe inspector needs to examine the records for induction and vessel-specific training. If the heavy lift vessel is semi-\nsubmersible, the BCO should be capable of taking the unit to survival draft if necessary.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08F","section_number":8,"section_letter":"F","section_title":"Cargo Operation - Heavy lift vessel","printed_question_no":"8.10","internal_question_no":"08F.010","question_sort_key":8601000.365,"question_text":"Does the latest cargo operation plan include stress and stability information, have the relevant calculations been carried out for the current operation, and are the BCOs fully aware of any operational limitations?","guide_to_inspection":"Inspectors should verify that stress and stability calculations have been completed prior to cargo transfer, encompassing the\ninitial, intermediate, and final stages. Continuous monitoring throughout the operation is essential to ensure conditions remain\nwithin the vessel’s design limits.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":167,"source_page_end":167,"raw_source_text":"Does the latest cargo operation plan include stress and stability information, have the relevant calculations\nbeen carried out for the current operation, and are the BCOs fully aware of any operational limitations? (V)\nGuide to Inspection\nInspectors should verify that stress and stability calculations have been completed prior to cargo transfer, encompassing the\ninitial, intermediate, and final stages. Continuous monitoring throughout the operation is essential to ensure conditions remain\nwithin the vessel’s design limits.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08F","section_number":8,"section_letter":"F","section_title":"Cargo Operation - Heavy lift vessel","printed_question_no":"8.11","internal_question_no":"08F.011","question_sort_key":8601100.366,"question_text":"Is there a calibrated inclinometer positioned near the ballast control panel?","guide_to_inspection":"","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"not_provided","source_page_start":167,"source_page_end":167,"raw_source_text":"Is there a calibrated inclinometer positioned near the ballast control panel? (V)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08F","section_number":8,"section_letter":"F","section_title":"Cargo Operation - Heavy lift vessel","printed_question_no":"8.12","internal_question_no":"08F.012","question_sort_key":8601200.367,"question_text":"Is the draft remote gauging system in good condition, and does it accurately reflect the vessel’s actual draft?","guide_to_inspection":"The vessel’s manager should establish the procedure for calibrating the remote draft gauging system and for regular\nmaintenance according to the manufacturer’s guidelines. The inspector should cross-reference the visual readings with the\nremote draft gauging system.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":167,"source_page_end":167,"raw_source_text":"Is the draft remote gauging system in good condition, and does it accurately reflect the vessel’s actual draft? (V)\nGuide to Inspection\nThe vessel’s manager should establish the procedure for calibrating the remote draft gauging system and for regular\nmaintenance according to the manufacturer’s guidelines. The inspector should cross-reference the visual readings with the\nremote draft gauging system.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08F","section_number":8,"section_letter":"F","section_title":"Cargo Operation - Heavy lift vessel","printed_question_no":"8.13","internal_question_no":"08F.013","question_sort_key":8601300.368,"question_text":"Are the tank remote gauging systems, including the level alarms, regularly maintained and calibrated according to the manufacturer’s recommendations, is there objective evidence confirming the regular verification, calibration of tank gauging systems, and testing of level alarms?","guide_to_inspection":"Tanks should be manually checked at least once a week, and the readings should be compared to those from remote gauges.\nDiscrepancies should be documented and accessible to the BCO.\nThe sounding tubes must be clear, and the sounding pipes should be labelled to indicate the tank they serve, as well as being\nequipped with a cap.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":168,"source_page_end":168,"raw_source_text":"Are the tank remote gauging systems, including the level alarms, regularly maintained and calibrated according\nto the manufacturer’s recommendations, is there objective evidence confirming the regular verification, calibration\nof tank gauging systems, and testing of level alarms? (V)\nGuide to Inspection\nTanks should be manually checked at least once a week, and the readings should be compared to those from remote gauges.\nDiscrepancies should be documented and accessible to the BCO.\nThe sounding tubes must be clear, and the sounding pipes should be labelled to indicate the tank they serve, as well as being\nequipped with a cap.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09A","section_number":9,"section_letter":"A","section_title":"Hatch Cover and Lifting Appliances","printed_question_no":"9.1","internal_question_no":"09A.001","question_sort_key":9100100.369,"question_text":"Are the cargo holds, including the underside of hatch covers, free of loose rust scale and paint flakes?","guide_to_inspection":"Underside and internal structure of hatch panel should be free of loose rust scale, paint flakes or blistering of paint coatings.\nHatch covers with a double skin, in the form of a closed box, are filled with inert gas. After structural repair, the inner spaces must\nbe re-inerted. This is done by inserting special tablets (available from the hatch cover manufacturer) into the space and welding\nshut. Never allow water to penetrate the box construction.\n(A master’s guide to hatch cover maintenance, 2002)\nIn general, the holds should be cleaned so that there are no residues of previous cargoes, no loose rust scale, paint flakes or\nblistering of paint coatings.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":169,"source_page_end":169,"raw_source_text":"Are the cargo holds, including the underside of hatch covers, free of loose rust scale and paint flakes? (V)\nGuide to Inspection\nUnderside and internal structure of hatch panel should be free of loose rust scale, paint flakes or blistering of paint coatings.\nHatch covers with a double skin, in the form of a closed box, are filled with inert gas. After structural repair, the inner spaces must\nbe re-inerted. This is done by inserting special tablets (available from the hatch cover manufacturer) into the space and welding\nshut. Never allow water to penetrate the box construction.\n(A master’s guide to hatch cover maintenance, 2002)\nIn general, the holds should be cleaned so that there are no residues of previous cargoes, no loose rust scale, paint flakes or\nblistering of paint coatings.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09A","section_number":9,"section_letter":"A","section_title":"Hatch Cover and Lifting Appliances","printed_question_no":"9.2","internal_question_no":"09A.002","question_sort_key":9100200.37,"question_text":"Is there a procedure in place for the safe operation and inspection of hatch covers and, has the Master/Chief Officer received appropriate training in hatch cover inspection and maintenance?","guide_to_inspection":"RightShip recommends the Master and Chief Officer complete a hatch cover inspection and maintenance training course pertinent\nto the type installed on the vessel being inspected. The focus of the course should be to familiarise them with the operational\nprinciples, limitations, maintenance requirements, and occupational safety considerations related to the shipboard installations.\nWhere not bespoke, the formal training course can be of a generic nature but this must be supplemented with type-specific\nmaterial for the hatch covers fitted. The vessel’s manager should strongly consider using audiovisual materials, as they have been\nproven to enhance knowledge retention and the learning experience.\nThe term “Audiovisual” is used to describe the combination of audio, video, and digital technologies that deliver information in an\nengaging and creative manner, assisting learners in better understanding concepts.\nParticipants should receive a training certificate(s) that clearly indicates the duration of the course(s), method of delivery, provider,\ntype of hatch cover (where applicable) and date of training.\nRecord which officers have undergone Hatch Cover Inspection and Maintenance Training and the nature of such training.\nRubber Packing: The design compression of rubber packing in a hatch cover, as specified by the manufacturer, can be found in the\nmanufacturer’s hatch cover manual along with other design criteria for the specific rubber packing.\nBearing Pads: Bearing pads will wear down based on their type, age, and the loads acting upon them. As bearing pads wear down,\nthe compression of the packing rubber will increase; therefore, the wear process should be regularly monitored by checking the skirt\nclearance. Information regarding the skirt clearance and maximum allowed wear on the bearing pads can be found in the manual.\nLocators: The locators (sliding positioners) ensure that the panels are properly guided and positioned when being closed. This\nmeans that the packing rubber at panel intersections is properly compressed up to the manufacturer’s design compression and\nthat panels are properly aligned and centred. The locators are important for achieving tightness; therefore, regular inspection and\nmeasurement of clearance are required.\nStoppers: Once the hatch cover is properly closed in port (static condition), the panels should remain in their correct sealing\nposition throughout the voyage while the ship is in a dynamic condition at sea. Relative movements will tend to distort the panel\narrangement, alignment, and geometry, but to prevent forces acting on the hull girder from being transferred directly into the\npanels, some limited movement should be allowed. The clearance of these stoppers, sometimes called rolling or pitching stoppers\ndepending on their working condition, should be measured regularly.\nThe vessel manager should establish a procedure and ensure that the clearance measurements of hatch cover components are\ncarried out regularly every six months.\nThe Master and/or Chief Officer shall be able to produce appropriate documentation that Hatch Cover Inspection and Maintenance\nTraining has been undertaken.\nThe training should provide the ship’s staff with some useful information on the role of key elements, such as what to look for, how\nto undertake a proper inspection prior to sea passage and make corresponding entries in the logbook as ultimate proof of due\ndiligence, which would greatly contribute to ship and cargo safety.\nOn vessels with hatch covers, the SMS should include the following:\n> A risk assessment for opening and closing hatch covers and working in cargo holds;\n> Instructions and procedures to ensure the safe operation of hatch covers and associated equipment; and\n> Defined levels of authority and lines of communication amongst shipboard personnel during such activities.\nThe procedure should emphasize the following points:\n> Assuring hatch covers are secured at all times, whether open or closed, unless they are being operated;\n> Keeping employees away from moving or pressured machinery; and\n> Practicing safe working at height techniques when working near an open hatch cover.\n> Communication between seafarers is critical for the safe operation of hatch covers. Coordination between the crews of\nvessels and establishing an environment where crew members speak out when they sense something risky can help\nprevent these types of serious incidents.\n> Attention is drawn to the dangers of proceeding to sea without fully secured hatch covers. Securing of all covers shall\nalways be completed before the commencement of a sea passage.\n> During voyages, especially on loaded passages, cover securing devices and tightness of cleating and securing\narrangements shall be checked, especially in anticipation of, and following periods of, severe weather.\n> Voyage checks shall consist of an external examination of the closed hatch covers and securing arrangements in\nanticipation of, and after, heavy weather but in any event at least once a week, weather permitting. Particular attention shall\nbe paid to the condition of hatch covers in the forward 25% of the ship’s length, where sea loads are normally greatest.\n(Annex 2 resolution MSC.169(79) 2004)\nSubject to meeting any special provisions detailed in the manufacturer’s operation manual, hatch covers should only be opened\non passage, when necessary, during favorable sea and weather conditions.\nEach vessel should carry and maintain an up-to-date list of the minimum recommended spare parts for the safe operation and\nto support both planned and corrective maintenance of type of hatch cover, as specified by the manufacturer.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":169,"source_page_end":170,"raw_source_text":"Is there a procedure in place for the safe operation and inspection of hatch covers and, has the\nMaster/Chief Officer received appropriate training in hatch cover inspection and maintenance?\nGuide to Inspection\nRightShip recommends the Master and Chief Officer complete a hatch cover inspection and maintenance training course pertinent\nto the type installed on the vessel being inspected. The focus of the course should be to familiarise them with the operational\nprinciples, limitations, maintenance requirements, and occupational safety considerations related to the shipboard installations.\nWhere not bespoke, the formal training course can be of a generic nature but this must be supplemented with type-specific\nmaterial for the hatch covers fitted. The vessel’s manager should strongly consider using audiovisual materials, as they have been\nproven to enhance knowledge retention and the learning experience.\nThe term “Audiovisual” is used to describe the combination of audio, video, and digital technologies that deliver information in an\nengaging and creative manner, assisting learners in better understanding concepts.\nParticipants should receive a training certificate(s) that clearly indicates the duration of the course(s), method of delivery, provider,\ntype of hatch cover (where applicable) and date of training.\nRecord which officers have undergone Hatch Cover Inspection and Maintenance Training and the nature of such training.\nRubber Packing: The design compression of rubber packing in a hatch cover, as specified by the manufacturer, can be found in the\nmanufacturer’s hatch cover manual along with other design criteria for the specific rubber packing.\nBearing Pads: Bearing pads will wear down based on their type, age, and the loads acting upon them. As bearing pads wear down,\nthe compression of the packing rubber will increase; therefore, the wear process should be regularly monitored by checking the skirt\nclearance. Information regarding the skirt clearance and maximum allowed wear on the bearing pads can be found in the manual.\nLocators: The locators (sliding positioners) ensure that the panels are properly guided and positioned when being closed. This\nmeans that the packing rubber at panel intersections is properly compressed up to the manufacturer’s design compression and\nthat panels are properly aligned and centred. The locators are important for achieving tightness; therefore, regular inspection and\nmeasurement of clearance are required.\nStoppers: Once the hatch cover is properly closed in port (static condition), the panels should remain in their correct sealing\nposition throughout the voyage while the ship is in a dynamic condition at sea. Relative movements will tend to distort the panel\narrangement, alignment, and geometry, but to prevent forces acting on the hull girder from being transferred directly into the\npanels, some limited movement should be allowed. The clearance of these stoppers, sometimes called rolling or pitching stoppers\ndepending on their working condition, should be measured regularly.\nThe vessel manager should establish a procedure and ensure that the clearance measurements of hatch cover components are\ncarried out regularly every six months.\nThe Master and/or Chief Officer shall be able to produce appropriate documentation that Hatch Cover Inspection and Maintenance\nTraining has been undertaken.\nThe training should provide the ship’s staff with some useful information on the role of key elements, such as what to look for, how\nto undertake a proper inspection prior to sea passage and make corresponding entries in the logbook as ultimate proof of due\ndiligence, which would greatly contribute to ship and cargo safety.\nOn vessels with hatch covers, the SMS should include the following:\n> A risk assessment for opening and closing hatch covers and working in cargo holds;\n> Instructions and procedures to ensure the safe operation of hatch covers and associated equipment; and\n> Defined levels of authority and lines of communication amongst shipboard personnel during such activities.\nThe procedure should emphasize the following points:\n> Assuring hatch covers are secured at all times, whether open or closed, unless they are being operated;\n> Keeping employees away from moving or pressured machinery; and\n> Practicing safe working at height techniques when working near an open hatch cover.\n> Communication between seafarers is critical for the safe operation of hatch covers. Coordination between the crews of\nvessels and establishing an environment where crew members speak out when they sense something risky can help\nprevent these types of serious incidents.\n> Attention is drawn to the dangers of proceeding to sea without fully secured hatch covers. Securing of all covers shall\nalways be completed before the commencement of a sea passage.\n> During voyages, especially on loaded passages, cover securing devices and tightness of cleating and securing\narrangements shall be checked, especially in anticipation of, and following periods of, severe weather.\n> Voyage checks shall consist of an external examination of the closed hatch covers and securing arrangements in\nanticipation of, and after, heavy weather but in any event at least once a week, weather permitting. Particular attention shall\nbe paid to the condition of hatch covers in the forward 25% of the ship’s length, where sea loads are normally greatest.\n(Annex 2 resolution MSC.169(79) 2004)\nSubject to meeting any special provisions detailed in the manufacturer’s operation manual, hatch covers should only be opened\non passage, when necessary, during favorable sea and weather conditions.\nEach vessel should carry and maintain an up-to-date list of the minimum recommended spare parts for the safe operation and\nto support both planned and corrective maintenance of type of hatch cover, as specified by the manufacturer.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09A","section_number":9,"section_letter":"A","section_title":"Hatch Cover and Lifting Appliances","printed_question_no":"9.3","internal_question_no":"09A.003","question_sort_key":9100300.371,"question_text":"Are adequate procedures in place for carrying out hose and / or ultrasonic testing of hatch covers and is documented evidence of such testing available?","guide_to_inspection":"RightShip recommends that the weather tightness of hatch covers should be checked at least once every 3 months. Record the\ndate and type of last test in comment.\nIn case of steel cargo shipment, weather tightness of hatch covers should be carried out by means of ultrasonic testing, before\nloading and in the presence of the loading surveyor.\nThe “means for securing weather-tightness” of hatch covers is defined in regulation 16.4 of the load line convention which\nstates: “The means for securing and maintaining weather-tightness shall be to the satisfaction of the Administration. The\narrangements shall ensure that the tightness can be maintained in any sea conditions, and for this purpose tests for tightness\nshall be required at the initial survey and may be required at periodical surveys and at annual inspections or at more frequent\nintervals.”\n(Load Lines, 2005)\nThe following parameters can be used for a hose test: Water pressure 2 bar, Nozzle size 15 - 18 mm, Spraying distance 1 - 1.5 m.\n(Wet Damage on Bulk Carriers, 2018)\nWhen carrying out an ultrasonic test, the instructions of the manufacturer should be followed. The transmitter is first placed in\nthe cargo compartment, an open hatch value (OHV) is then obtained, after which the detector is passed along each seal in turn\nto find any leakage of ultrasonic sound. When the test is completed, any area giving reading in excess of 10% OHV, indicates\na point where water ingress is possible. The use of ultrasonic testing equipment operated by a certified person is widely\nrecommended when weather tightness testing of hatch covers is required. (Bulk Cargoes: A Guide to Good Practice, 2016)\nThe tests are only part of the loss-prevention process. Well-maintained seals, cleats, supports, drains and other hatch cover\ncomponents are the key to achieving weather tightness.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":170,"source_page_end":170,"raw_source_text":"Are adequate procedures in place for carrying out hose and / or ultrasonic testing of hatch covers\nand is documented evidence of such testing available? (V)\nGuide to Inspection\nRightShip recommends that the weather tightness of hatch covers should be checked at least once every 3 months. Record the\ndate and type of last test in comment.\nIn case of steel cargo shipment, weather tightness of hatch covers should be carried out by means of ultrasonic testing, before\nloading and in the presence of the loading surveyor.\nThe “means for securing weather-tightness” of hatch covers is defined in regulation 16.4 of the load line convention which\nstates: “The means for securing and maintaining weather-tightness shall be to the satisfaction of the Administration. The\narrangements shall ensure that the tightness can be maintained in any sea conditions, and for this purpose tests for tightness\nshall be required at the initial survey and may be required at periodical surveys and at annual inspections or at more frequent\nintervals.”\n(Load Lines, 2005)\nThe following parameters can be used for a hose test: Water pressure 2 bar, Nozzle size 15 - 18 mm, Spraying distance 1 - 1.5 m.\n(Wet Damage on Bulk Carriers, 2018)\nWhen carrying out an ultrasonic test, the instructions of the manufacturer should be followed. The transmitter is first placed in\nthe cargo compartment, an open hatch value (OHV) is then obtained, after which the detector is passed along each seal in turn\nto find any leakage of ultrasonic sound. When the test is completed, any area giving reading in excess of 10% OHV, indicates\na point where water ingress is possible. The use of ultrasonic testing equipment operated by a certified person is widely\nrecommended when weather tightness testing of hatch covers is required. (Bulk Cargoes: A Guide to Good Practice, 2016)\nThe tests are only part of the loss-prevention process. Well-maintained seals, cleats, supports, drains and other hatch cover\ncomponents are the key to achieving weather tightness.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09A","section_number":9,"section_letter":"A","section_title":"Hatch Cover and Lifting Appliances","printed_question_no":"9.4","internal_question_no":"09A.004","question_sort_key":9100400.372,"question_text":"Are the compression bars and the coaming tops’ water channels clean, free of corrosion and maintained in good condition?","guide_to_inspection":"Effective sealing is only possible with a straight, undamaged, and non-corroded compression bar. Compression bars which are\nnot in this condition should be repaired or replaced, taking care to align the bars properly.\nHatch coaming tops and the double drainage channels should be clean, free of corrosion and obstructions.\n(Hatch Cover Maintenance, 2015)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":170,"source_page_end":170,"raw_source_text":"Are the compression bars and the coaming tops’ water channels clean, free of corrosion and\nmaintained in good condition? (V)\nGuide to Inspection\nEffective sealing is only possible with a straight, undamaged, and non-corroded compression bar. Compression bars which are\nnot in this condition should be repaired or replaced, taking care to align the bars properly.\nHatch coaming tops and the double drainage channels should be clean, free of corrosion and obstructions.\n(Hatch Cover Maintenance, 2015)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09A","section_number":9,"section_letter":"A","section_title":"Hatch Cover and Lifting Appliances","printed_question_no":"9.5","internal_question_no":"09A.005","question_sort_key":9100500.373,"question_text":"Are the drain holes of coamings clean, the inboard coamings faces free from any vertical rust staining and are the non-return valves in good condition?","guide_to_inspection":"Damaged, missing, or defective non-return drain valves should be repaired or renewed. Where applicable, the fire cap of the drain\nvalve should be firmly connected by a lanyard to the valve and maintained in good condition.\nCheck that the drainpipes and drain valves are not clogged. Maintenance of non-return valve should be incorporated in the plan\nmaintenance system.\nAny rust stains on the inboard coaming could be a sign of water leakage, especially at the cross-joints or split-joints.\n(Hatch Cover Maintenance, 2015)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":171,"source_page_end":171,"raw_source_text":"Are the drain holes of coamings clean, the inboard coamings faces free from any vertical rust\nstaining and are the non-return valves in good condition? (V)\nGuide to Inspection\nDamaged, missing, or defective non-return drain valves should be repaired or renewed. Where applicable, the fire cap of the drain\nvalve should be firmly connected by a lanyard to the valve and maintained in good condition.\nCheck that the drainpipes and drain valves are not clogged. Maintenance of non-return valve should be incorporated in the plan\nmaintenance system.\nAny rust stains on the inboard coaming could be a sign of water leakage, especially at the cross-joints or split-joints.\n(Hatch Cover Maintenance, 2015)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09A","section_number":9,"section_letter":"A","section_title":"Hatch Cover and Lifting Appliances","printed_question_no":"9.6","internal_question_no":"09A.006","question_sort_key":9100600.374,"question_text":"Are quick-acting cleats and crutches all in place and in good working condition with the rubber washers flexible and free from paint and cracks?","guide_to_inspection":"Quick acting cleats should be fitted at their original positions free of any corrosion or bending. The rubber washers that are fitted\nto the cleats should have proper elasticity. Other component parts to which cleats are welded or acting on such as coaming\ntable, crutches, snugs, panel side plating should be in good condition.\n(Hatch Cover Maintenance, 2015)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":171,"source_page_end":171,"raw_source_text":"Are quick-acting cleats and crutches all in place and in good working condition with the rubber\nwashers flexible and free from paint and cracks? (V)\nGuide to Inspection\nQuick acting cleats should be fitted at their original positions free of any corrosion or bending. The rubber washers that are fitted\nto the cleats should have proper elasticity. Other component parts to which cleats are welded or acting on such as coaming\ntable, crutches, snugs, panel side plating should be in good condition.\n(Hatch Cover Maintenance, 2015)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09A","section_number":9,"section_letter":"A","section_title":"Hatch Cover and Lifting Appliances","printed_question_no":"9.7","internal_question_no":"09A.007","question_sort_key":9100700.375,"question_text":"If the hatch panel side and end plates are in steel-to-steel contact with the coaming tops when closed, are the coaming tops free from grooving or wear?","guide_to_inspection":"","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"not_provided","source_page_start":171,"source_page_end":171,"raw_source_text":"If the hatch panel side and end plates are in steel-to-steel contact with the coaming tops when\nclosed, are the coaming tops free from grooving or wear? (V)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09A","section_number":9,"section_letter":"A","section_title":"Hatch Cover and Lifting Appliances","printed_question_no":"9.8","internal_question_no":"09A.008","question_sort_key":9100800.376,"question_text":"If the hatch covers are supported by bearing pads, are they free from wear or damage?","guide_to_inspection":"Bearing pads are fine pieces of engineering and replacing them with non-original spares or non-compatible steel could result in\nserious problems. Often bearing pads are replaced or repaired by the ship’s crew with only one thing in mind, i.e., restoring the\nheight of the bearing pads, whereby the correct size and use of appropriate material for the mating surfaces is overlooked. For\nbearing pad adjustment it is strongly recommended that manufacturers or specialists are called in for advice.\n(Hatch Cover Maintenance, 2015) (Vervloesem, 2017)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":171,"source_page_end":171,"raw_source_text":"If the hatch covers are supported by bearing pads, are they free from\nwear or damage? (V)\nGuide to Inspection\nBearing pads are fine pieces of engineering and replacing them with non-original spares or non-compatible steel could result in\nserious problems. Often bearing pads are replaced or repaired by the ship’s crew with only one thing in mind, i.e., restoring the\nheight of the bearing pads, whereby the correct size and use of appropriate material for the mating surfaces is overlooked. For\nbearing pad adjustment it is strongly recommended that manufacturers or specialists are called in for advice.\n(Hatch Cover Maintenance, 2015) (Vervloesem, 2017)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09A","section_number":9,"section_letter":"A","section_title":"Hatch Cover and Lifting Appliances","printed_question_no":"9.9","internal_question_no":"09A.009","question_sort_key":9100900.377,"question_text":"Are the side and cross-joint rubber seals in good condition?","guide_to_inspection":"Packing rubbers are designed to be compressed to a certain depth, which is generally referred to as the design compression\n(rule of thumb for estimating the design compression of ordinary box-type packing rubbers is as follows: design compression\n= 25% of the nominal thickness of the packing rubber). Depending on the type of rubber packing, design compression will\ngenerally be in the range of 4-20mm, and this is either specified in the maker’s manual or indicated in the drawing.\nThe minimum length of replaced rubber packing should be one metre.\nRubber packing and adhesive has a limited shelf life, so check the date stamp and discard if beyond the use-by date.\nManufacturers approved spare parts should be used.\nThe corner pads, joints and end pieces of rubber sealing should be intact, properly glued and in the correct position.\nWhenever packing rubbers need replacing, it is extremely important to ensure that not only are the dimensions compatible, but\nalso that the alternative product will meet with the required performance criteria.\n(Hatch Cover Maintenance, 2015) (Vervloesem, 2017)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":171,"source_page_end":171,"raw_source_text":"Are the side and cross-joint rubber seals in good condition? (V)\nGuide to Inspection\nPacking rubbers are designed to be compressed to a certain depth, which is generally referred to as the design compression\n(rule of thumb for estimating the design compression of ordinary box-type packing rubbers is as follows: design compression\n= 25% of the nominal thickness of the packing rubber). Depending on the type of rubber packing, design compression will\ngenerally be in the range of 4-20mm, and this is either specified in the maker’s manual or indicated in the drawing.\nThe minimum length of replaced rubber packing should be one metre.\nRubber packing and adhesive has a limited shelf life, so check the date stamp and discard if beyond the use-by date.\nManufacturers approved spare parts should be used.\nThe corner pads, joints and end pieces of rubber sealing should be intact, properly glued and in the correct position.\nWhenever packing rubbers need replacing, it is extremely important to ensure that not only are the dimensions compatible, but\nalso that the alternative product will meet with the required performance criteria.\n(Hatch Cover Maintenance, 2015) (Vervloesem, 2017)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09A","section_number":9,"section_letter":"A","section_title":"Hatch Cover and Lifting Appliances","printed_question_no":"9.10","internal_question_no":"09A.010","question_sort_key":9101000.378,"question_text":"Are hatch cover panels free of misalignment?","guide_to_inspection":"The permanent deflection of rubber seals should be in the centre of the rubber and not to one side. Non-central permanent set\nmay indicate misalignment of panel.\n(Hatch Cover Maintenance, 2015)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":172,"source_page_end":172,"raw_source_text":"Are hatch cover panels free of misalignment? (V)\nGuide to Inspection\nThe permanent deflection of rubber seals should be in the centre of the rubber and not to one side. Non-central permanent set\nmay indicate misalignment of panel.\n(Hatch Cover Maintenance, 2015)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09A","section_number":9,"section_letter":"A","section_title":"Hatch Cover and Lifting Appliances","printed_question_no":"9.11","internal_question_no":"09A.011","question_sort_key":9101100.379,"question_text":"Are seal retaining channels in good condition and free of corrosion?","guide_to_inspection":"Where the rubber seal retaining channel (socket) is corroded, rubber gaskets cannot be stuck in the socket, and consequently\nwill lose their function.\n(Marine Order 32 (Cargo handling equipment) 2016, 2017)\nThe sides of the panels in the way of the rubber seal retaining channel and edges should be in good condition and free from\ndistortion.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":172,"source_page_end":172,"raw_source_text":"Are seal retaining channels in good condition and free of corrosion? (V)\nGuide to Inspection\nWhere the rubber seal retaining channel (socket) is corroded, rubber gaskets cannot be stuck in the socket, and consequently\nwill lose their function.\n(Marine Order 32 (Cargo handling equipment) 2016, 2017)\nThe sides of the panels in the way of the rubber seal retaining channel and edges should be in good condition and free from\ndistortion.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09A","section_number":9,"section_letter":"A","section_title":"Hatch Cover and Lifting Appliances","printed_question_no":"9.12","internal_question_no":"09A.012","question_sort_key":9101200.38,"question_text":"Are the cross-joint seal retaining channels and the cross-joint compression bar straight, free of corrosion and damage, and are the channel supports and brackets in good condition?","guide_to_inspection":"","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"not_provided","source_page_start":172,"source_page_end":172,"raw_source_text":"Are the cross-joint seal retaining channels and the cross-joint compression bar straight, free of\ncorrosion and damage, and are the channel supports and brackets in good condition? (V)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09A","section_number":9,"section_letter":"A","section_title":"Hatch Cover and Lifting Appliances","printed_question_no":"9.13","internal_question_no":"09A.013","question_sort_key":9101300.381,"question_text":"Are the following parts of the hatch covers, where applicable, all in good order and do they appear to be well maintained? (V) > Wheels/bearings or trackway > Hydraulic system including hoses > Chains > Link pin and safety pin > Cargo holds’ ventilator on the side and end of hatch panel","guide_to_inspection":"When agreeable by Master, inspectors are required to seek that the hydraulic hose protector’s wrapping be removed at random\nin order to conduct a visual and random check of these pipes.”\nHydraulic hoses shall be inspected and replaced in accordance with manufacturer recommendations; in the absence of\nmanufacturer recommendations, ISO/TS 171652:2018 table 1 and clause 8 shall be followed. The requirements for hydraulic\nhose maintenance must be included into the PMS. RightShip recommends that all flexible hydraulic hoses exposed on deck be\nreplaced at least every 5 years.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":172,"source_page_end":172,"raw_source_text":"Are the following parts of the hatch covers, where applicable, all in good order and do they appear\nto be well maintained? (V)\n> Wheels/bearings or trackway\n> Hydraulic system including hoses\n> Chains\n> Link pin and safety pin\n> Cargo holds’ ventilator on the side and end of hatch panel\nGuide to Inspection\nWhen agreeable by Master, inspectors are required to seek that the hydraulic hose protector’s wrapping be removed at random\nin order to conduct a visual and random check of these pipes.”\nHydraulic hoses shall be inspected and replaced in accordance with manufacturer recommendations; in the absence of\nmanufacturer recommendations, ISO/TS 171652:2018 table 1 and clause 8 shall be followed. The requirements for hydraulic\nhose maintenance must be included into the PMS. RightShip recommends that all flexible hydraulic hoses exposed on deck be\nreplaced at least every 5 years.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09A","section_number":9,"section_letter":"A","section_title":"Hatch Cover and Lifting Appliances","printed_question_no":"9.14","internal_question_no":"09A.014","question_sort_key":9101400.382,"question_text":"Are cross-joint wedges and their wedge bridge (where fitted) in place, operational and effective?","guide_to_inspection":"","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"not_provided","source_page_start":172,"source_page_end":172,"raw_source_text":"Are cross-joint wedges and their wedge bridge (where fitted) in place, operational and effective? (V)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09A","section_number":9,"section_letter":"A","section_title":"Hatch Cover and Lifting Appliances","printed_question_no":"9.15","internal_question_no":"09A.015","question_sort_key":9101500.383,"question_text":"If hatch covers are hydraulically operated, has the hydraulic oil been tested regularly for contamination and deterioration?","guide_to_inspection":"The oil tank of the hydraulic system should be kept filled to the operating level and with hydraulic oil recommended by the\nmanufacturer. The cleanliness and viscosity of hydraulic oil must be checked. Samples of the oil should be sent to a chemist for testing\nas per manufacturer recommendation. The hydraulic system is provided with bleed points.\nHydraulic oil should be replaced every five years or sooner if significant repairs have been carried out, such as piping or\ncylinder replacement. Hydraulic oil filters should be changed every twelve months or in accordance with the manufacturer’s\nrecommendations.\nIf the vessel’s manager has a procedure in place for regular hydraulic oil analysis and the results confirm the oil remains within\nacceptable limits, the renewal interval may be extended, provided this does not exceed the maximum lifespan specified by the\noil manufacturer. Objective evidence should include documented analysis results and confirmation from the oil manufacturer\nsupporting continued use within the approved limits. All extensions should be recorded and retained for verification\nIn addition to the Elemental and Contaminant tests, the hydraulic oil of the hatch cover system shall also be subjected to a\nParticle Count test.\nIt is essential that samples be taken from the proper location inside the system, and not from any bleed point. As bleed points\nexist just for captive loop or dead end air removal.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V & M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":173,"source_page_end":173,"raw_source_text":"If hatch covers are hydraulically operated, has the hydraulic oil been tested regularly for contamination\nand deterioration? (V & M)\nGuide to Inspection\nThe oil tank of the hydraulic system should be kept filled to the operating level and with hydraulic oil recommended by the\nmanufacturer. The cleanliness and viscosity of hydraulic oil must be checked. Samples of the oil should be sent to a chemist for testing\nas per manufacturer recommendation. The hydraulic system is provided with bleed points.\nHydraulic oil should be replaced every five years or sooner if significant repairs have been carried out, such as piping or\ncylinder replacement. Hydraulic oil filters should be changed every twelve months or in accordance with the manufacturer’s\nrecommendations.\nIf the vessel’s manager has a procedure in place for regular hydraulic oil analysis and the results confirm the oil remains within\nacceptable limits, the renewal interval may be extended, provided this does not exceed the maximum lifespan specified by the\noil manufacturer. Objective evidence should include documented analysis results and confirmation from the oil manufacturer\nsupporting continued use within the approved limits. All extensions should be recorded and retained for verification\nIn addition to the Elemental and Contaminant tests, the hydraulic oil of the hatch cover system shall also be subjected to a\nParticle Count test.\nIt is essential that samples be taken from the proper location inside the system, and not from any bleed point. As bleed points\nexist just for captive loop or dead end air removal.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09A","section_number":9,"section_letter":"A","section_title":"Hatch Cover and Lifting Appliances","printed_question_no":"9.16","internal_question_no":"09A.016","question_sort_key":9101600.384,"question_text":"Are officers familiar with emergency hatch cover operation arrangements and is there evidence of effective training of personnel available on board?","guide_to_inspection":"The emergency hatch cover operation procedure should be incorporated in the ship’s manual.\nEmergency or auxiliary operation of hatch covers can be executed either by traditional hand pumps and wire pullers or by\nportable electric pump units, connected either to the on-board electric power system or to shore.\nThe portable electric pump unit makes the operation easy, swift and safe, as the unit is connected directly to the control stand\nwith quick couplings including all safety enhancing valves active.\nRightship recommends vessels to carry an emergency portable pump unit (portable electric and/or hydraulic type) for situations\nwhen the standard pump unit cannot be used. The manufacturers’ instructions for the maintenance and test of the emergency\nportable pump unit shall be incorporated in the PMS.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":173,"source_page_end":173,"raw_source_text":"Are officers familiar with emergency hatch cover operation arrangements and is there evidence\nof effective training of personnel available on board? (V)\nGuide to Inspection\nThe emergency hatch cover operation procedure should be incorporated in the ship’s manual.\nEmergency or auxiliary operation of hatch covers can be executed either by traditional hand pumps and wire pullers or by\nportable electric pump units, connected either to the on-board electric power system or to shore.\nThe portable electric pump unit makes the operation easy, swift and safe, as the unit is connected directly to the control stand\nwith quick couplings including all safety enhancing valves active.\nRightship recommends vessels to carry an emergency portable pump unit (portable electric and/or hydraulic type) for situations\nwhen the standard pump unit cannot be used. The manufacturers’ instructions for the maintenance and test of the emergency\nportable pump unit shall be incorporated in the PMS.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09A","section_number":9,"section_letter":"A","section_title":"Hatch Cover and Lifting Appliances","printed_question_no":"9.17","internal_question_no":"09A.017","question_sort_key":9101700.385,"question_text":"Has a thorough examination and load test of lifting appliances been carried out and is the record of the test and examination being maintained properly?","guide_to_inspection":"All lifting appliances and every item of loose gear shall be thoroughly examined by a competent person at least once in every\ntwelve months and five yearly load testing shall be carried out when the safe working load (SWL) of the lifting appliance is more\nthan one tonne. Flag State may impose the quadrennial load test for the lifting appliances.\nThe term “competent person” means a person possessing the knowledge and experience required for the performance of\nthorough examinations and tests of lifting appliances and loose gear and who is acceptable to the competent authority.\n(Register of Lifting Appliances and Items of Loose Gear, 1985)\nThe lifting appliance maintenance records should be updated and available on board.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V & M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":173,"source_page_end":173,"raw_source_text":"Has a thorough examination and load test of lifting appliances been carried out and is the record\nof the test and examination being maintained properly? (V & M)\nGuide to Inspection\nAll lifting appliances and every item of loose gear shall be thoroughly examined by a competent person at least once in every\ntwelve months and five yearly load testing shall be carried out when the safe working load (SWL) of the lifting appliance is more\nthan one tonne. Flag State may impose the quadrennial load test for the lifting appliances.\nThe term “competent person” means a person possessing the knowledge and experience required for the performance of\nthorough examinations and tests of lifting appliances and loose gear and who is acceptable to the competent authority.\n(Register of Lifting Appliances and Items of Loose Gear, 1985)\nThe lifting appliance maintenance records should be updated and available on board.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09A","section_number":9,"section_letter":"A","section_title":"Hatch Cover and Lifting Appliances","printed_question_no":"9.18","internal_question_no":"09A.018","question_sort_key":9101800.386,"question_text":"Are the hoist and luffing wires of cranes, where fitted, reported in good order and is there recorded evidence of regular inspection and maintenance?","guide_to_inspection":"Poor maintenance of wire leads to weakening of the wire over time. Inappropriate operation of the crane and incorrect use of the\nwire leads to damage being sustained by the wire. Wire ropes should be examined for defects, and if those defects are excessive,\nadvice should be obtained and/or the wire should be discarded. Example of defects that may be found on the wires are:\n1. Broken wires and fractured strands\n2. External and internal wear/corrosion\n3. Decrease in elasticity\n4. Kinks and other mechanical damages\nThere should be an appropriate test certificate for all wire ropes on board; that is for all of those in use and for all spare wire\nropes. The certificates should give the date of manufacture, the material strength, the construction of the wire and the breaking\nload test of a sample. There should be an inventory of all wire ropes on board and records of the dates of renewal of the wires in\nuse on all cranes.\n(Cranes, Their Operation and Reasons for Failures, 2015)\nSuch inspection should be included under the PMS system. Crane wires and sheaves should be in apparent satisfactory\ncondition.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":174,"source_page_end":174,"raw_source_text":"Are the hoist and luffing wires of cranes, where fitted, reported in good order and is there recorded\nevidence of regular inspection and maintenance? (V)\nGuide to Inspection\nPoor maintenance of wire leads to weakening of the wire over time. Inappropriate operation of the crane and incorrect use of the\nwire leads to damage being sustained by the wire. Wire ropes should be examined for defects, and if those defects are excessive,\nadvice should be obtained and/or the wire should be discarded. Example of defects that may be found on the wires are:\n1. Broken wires and fractured strands\n2. External and internal wear/corrosion\n3. Decrease in elasticity\n4. Kinks and other mechanical damages\nThere should be an appropriate test certificate for all wire ropes on board; that is for all of those in use and for all spare wire\nropes. The certificates should give the date of manufacture, the material strength, the construction of the wire and the breaking\nload test of a sample. There should be an inventory of all wire ropes on board and records of the dates of renewal of the wires in\nuse on all cranes.\n(Cranes, Their Operation and Reasons for Failures, 2015)\nSuch inspection should be included under the PMS system. Crane wires and sheaves should be in apparent satisfactory\ncondition.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09A","section_number":9,"section_letter":"A","section_title":"Hatch Cover and Lifting Appliances","printed_question_no":"9.19","internal_question_no":"09A.019","question_sort_key":9101900.387,"question_text":"Are the main structures, foundation structures and mountings of the cargo cranes free of apparent defect or damage?","guide_to_inspection":"Record a finding if the rocking test was not conducted at least once every six months.\nThe main structures, foundation structures and mountings should be inspected to determine whether any defects or damage\nare present and, if any such defects/damages are present, appropriate repairs should be carried out.\n(Cranes, Their Operation and Reasons for Failures, 2015)\nThe holding down bolts and slewing ring should be free of significant corrosion and crane access ladders and platforms in\napparent satisfactory condition.\nSuch routine inspections should be included under the PMS system.\nRocking Test\nTo ensure that slewing ring bearings are not becoming worn, the vessel’s planned maintenance system should include a rocking\ntest, and each crane tested every six months. A record of these tests must be entered into the Registry of Lifting Appliances. The\nrocking test comprises the measurement of the deflection between the crane pedestal and the rotating crane housing in the way\nof the slewing ring using a dial test indicator to determine the bearing clearances.\nMeasurements are taken at the two locations on the slewing ring susceptible to the most significant bearing wear, under the jib’s\ncentre and diametrically opposite. A set of eight readings are taken with the crane pointing dead ahead, dead astern, to port and\nthen to starboard, initially with the jib luffed to its minimum radius with no weight on the hook and then with the jib luffed to its\nmaximum radius with the difference between the two readings giving the bearing clearance. The readings are compared against\nthe manufacturer’s maximum permissible clearance, which will depend on the type and size of the slewing ring and bearing size.\nThe original bearing clearances should be available to determine the degree of wear. Consider shortening the testing intervals\nwhen the noted wear has increased appreciably between consecutive rocking tests. Some manufacturers have produced\nintegrated devices to measure unacceptable wear of the bearing in their slewing rings to provide early warning of excessive\nbearing wear.\n(Crane Slewing Gear Maintenance and Rocking Tests 2018)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":174,"source_page_end":174,"raw_source_text":"Are the main structures, foundation structures and mountings of the cargo cranes free of\napparent defect or damage? (V)\nGuide to Inspection\nRecord a finding if the rocking test was not conducted at least once every six months.\nThe main structures, foundation structures and mountings should be inspected to determine whether any defects or damage\nare present and, if any such defects/damages are present, appropriate repairs should be carried out.\n(Cranes, Their Operation and Reasons for Failures, 2015)\nThe holding down bolts and slewing ring should be free of significant corrosion and crane access ladders and platforms in\napparent satisfactory condition.\nSuch routine inspections should be included under the PMS system.\nRocking Test\nTo ensure that slewing ring bearings are not becoming worn, the vessel’s planned maintenance system should include a rocking\ntest, and each crane tested every six months. A record of these tests must be entered into the Registry of Lifting Appliances. The\nrocking test comprises the measurement of the deflection between the crane pedestal and the rotating crane housing in the way\nof the slewing ring using a dial test indicator to determine the bearing clearances.\nMeasurements are taken at the two locations on the slewing ring susceptible to the most significant bearing wear, under the jib’s\ncentre and diametrically opposite. A set of eight readings are taken with the crane pointing dead ahead, dead astern, to port and\nthen to starboard, initially with the jib luffed to its minimum radius with no weight on the hook and then with the jib luffed to its\nmaximum radius with the difference between the two readings giving the bearing clearance. The readings are compared against\nthe manufacturer’s maximum permissible clearance, which will depend on the type and size of the slewing ring and bearing size.\nThe original bearing clearances should be available to determine the degree of wear. Consider shortening the testing intervals\nwhen the noted wear has increased appreciably between consecutive rocking tests. Some manufacturers have produced\nintegrated devices to measure unacceptable wear of the bearing in their slewing rings to provide early warning of excessive\nbearing wear.\n(Crane Slewing Gear Maintenance and Rocking Tests 2018)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09A","section_number":9,"section_letter":"A","section_title":"Hatch Cover and Lifting Appliances","printed_question_no":"9.20","internal_question_no":"09A.020","question_sort_key":9102000.388,"question_text":"Is the cargo crane’s machinery and operator’s cab, including the operator’s cab controls, in good working order and inspected, tested, and maintained in accordance with manufacturer’s recommendations?","guide_to_inspection":"The inspection of the crane cabinet’s structural integrity should be included in the PMS.\nThe machinery of a crane includes all electrical control equipment and systems, all motors, hydraulic oil pumps, filters and\ncoolers, and winches, together with winch brakes and control gear, all limit switches, cut-out switches and other pieces of\nequipment. Routine maintenance of these various pieces of machinery is essential for their continuing correct operation. Such\nroutine inspection, testing and maintenance should be included under the PMS system as per manufacturer recommendation.\n(Cranes, Their Operation and Reasons for Failures, 2015)\nOperating instructions for use of a crane shall be posted inside the operator’s cab. The crane / derrick safety devices should be\nin apparent operation and regularly tested. The window wiper,window’s glass and driver’s chair should be maintained in good\ncondition.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":175,"source_page_end":175,"raw_source_text":"Is the cargo crane’s machinery and operator’s cab, including the operator’s cab controls, in good working\norder and inspected, tested, and maintained in accordance with manufacturer’s recommendations?\nGuide to Inspection\nThe inspection of the crane cabinet’s structural integrity should be included in the PMS.\nThe machinery of a crane includes all electrical control equipment and systems, all motors, hydraulic oil pumps, filters and\ncoolers, and winches, together with winch brakes and control gear, all limit switches, cut-out switches and other pieces of\nequipment. Routine maintenance of these various pieces of machinery is essential for their continuing correct operation. Such\nroutine inspection, testing and maintenance should be included under the PMS system as per manufacturer recommendation.\n(Cranes, Their Operation and Reasons for Failures, 2015)\nOperating instructions for use of a crane shall be posted inside the operator’s cab. The crane / derrick safety devices should be\nin apparent operation and regularly tested. The window wiper,window’s glass and driver’s chair should be maintained in good\ncondition.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09A","section_number":9,"section_letter":"A","section_title":"Hatch Cover and Lifting Appliances","printed_question_no":"9.21","internal_question_no":"09A.021","question_sort_key":9102100.389,"question_text":"Are the ship’s grabs being maintained as per manufacturer recommendations and have the maintenance requirements been incorporated in the PMS?","guide_to_inspection":"The ship’s grabs should be part of the ship’s planned maintenance system and routine inspections and maintenance should\nbe carried out. That routine maintenance and inspection regime should include the thorough inspection of all structures of\nthe grabs and their mechanical parts and of any associated equipment, including any umbilical cables and control systems to\nensure:\n1. All parts are without defect or damage\n2. Hydraulic oil reservoirs are filled to the appropriate level\n3. All machinery and control systems are functioning correctly, and\n4. All moving parts are free and well-greased.\nBefore each ship’s grab is taken into use for cargo operations, it should be rigged to the cargo hoist wire of the ship’s crane and\nshould be carefully tested to demonstrate its full functioning capability. A record of that testing should be kept.\nThe technical specification for a clamshell grab will include its capacity in cubic metres, its weight in tonnes, its dimensions\nin metres and details of its operation. The capacity might be a single figure, or might be two or more figures, if spill plates or\nmoveable panels are fitted to the grab, which can be removed or put in place to alter the capacity of the grab when closed. The\ncapacity of typical grabs used for the loading and discharging of bulk cargoes using ship’s cranes ranges from about 4m³ to\nabout 16m³. The weight of the grab might be about 2 tonnes or as much as 12 tonnes. This should be shown on the name plate\nattached to the grab.\nThe weight of cargo which can be lifted by a grab depends upon the capacity of the grab and the density, or the stowage factor,\nof the commodity. When calculating the weight of cargo lifted by a grab, it should be remembered that it is likely that the surface\nof the cargo in the grab will be slightly peaked or crowned; such that a greater weight than the volume of the grab might indicate\nwill be lifted. An allowance for this of 25% should be included in any calculation.\nIf the crane is designed for both hook operation and for grab operation, it is likely to be given two different SWL ratings by the\nmanufacturer – one for hook operations and one for grab operations. It is usual for the grab operation rating to be 20% less than\nthe hook operation rating. The two SWL ratings should be stated on the plate on the crane jib.\n(Cranes, Their Operation and Reasons for Failures, 2015)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":175,"source_page_end":175,"raw_source_text":"Are the ship’s grabs being maintained as per manufacturer recommendations and have the\nmaintenance requirements been incorporated in the PMS? (V)\nGuide to Inspection\nThe ship’s grabs should be part of the ship’s planned maintenance system and routine inspections and maintenance should\nbe carried out. That routine maintenance and inspection regime should include the thorough inspection of all structures of\nthe grabs and their mechanical parts and of any associated equipment, including any umbilical cables and control systems to\nensure:\n1. All parts are without defect or damage\n2. Hydraulic oil reservoirs are filled to the appropriate level\n3. All machinery and control systems are functioning correctly, and\n4. All moving parts are free and well-greased.\nBefore each ship’s grab is taken into use for cargo operations, it should be rigged to the cargo hoist wire of the ship’s crane and\nshould be carefully tested to demonstrate its full functioning capability. A record of that testing should be kept.\nThe technical specification for a clamshell grab will include its capacity in cubic metres, its weight in tonnes, its dimensions\nin metres and details of its operation. The capacity might be a single figure, or might be two or more figures, if spill plates or\nmoveable panels are fitted to the grab, which can be removed or put in place to alter the capacity of the grab when closed. The\ncapacity of typical grabs used for the loading and discharging of bulk cargoes using ship’s cranes ranges from about 4m³ to\nabout 16m³. The weight of the grab might be about 2 tonnes or as much as 12 tonnes. This should be shown on the name plate\nattached to the grab.\nThe weight of cargo which can be lifted by a grab depends upon the capacity of the grab and the density, or the stowage factor,\nof the commodity. When calculating the weight of cargo lifted by a grab, it should be remembered that it is likely that the surface\nof the cargo in the grab will be slightly peaked or crowned; such that a greater weight than the volume of the grab might indicate\nwill be lifted. An allowance for this of 25% should be included in any calculation.\nIf the crane is designed for both hook operation and for grab operation, it is likely to be given two different SWL ratings by the\nmanufacturer – one for hook operations and one for grab operations. It is usual for the grab operation rating to be 20% less than\nthe hook operation rating. The two SWL ratings should be stated on the plate on the crane jib.\n(Cranes, Their Operation and Reasons for Failures, 2015)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09A","section_number":9,"section_letter":"A","section_title":"Hatch Cover and Lifting Appliances","printed_question_no":"9.22","internal_question_no":"09A.022","question_sort_key":9102200.39,"question_text":"Are the loose gears of lifting appliances clearly marked and are the certificates of the loose gears available and traceable on board?","guide_to_inspection":"It is important that the loose gears used for lifting appliances (including deck cranes and the engine room crane) are marked\nclearly with its SWL and a batch mark or number, where that mark can be verified by a test certificate. RightShip recommends\nthat these test certificates are clearly labelled and kept in an easily accessible file. A method of correct identification and\nmatching of individual certificates with the loose gears should be established on board. Loose gears without certificates must\nnot be used on board.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":176,"source_page_end":176,"raw_source_text":"Are the loose gears of lifting appliances clearly marked and are the certificates of the loose gears\navailable and traceable on board? (V)\nGuide to Inspection\nIt is important that the loose gears used for lifting appliances (including deck cranes and the engine room crane) are marked\nclearly with its SWL and a batch mark or number, where that mark can be verified by a test certificate. RightShip recommends\nthat these test certificates are clearly labelled and kept in an easily accessible file. A method of correct identification and\nmatching of individual certificates with the loose gears should be established on board. Loose gears without certificates must\nnot be used on board.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09B","section_number":9,"section_letter":"B","section_title":"Gantry Cranes","printed_question_no":"9.1","internal_question_no":"09B.001","question_sort_key":9200100.391,"question_text":"Has the vessel been provided with procedures for the safe operation of the gantry crane?","guide_to_inspection":"The inspector should randomly check the implementation of the procedures.\nEvery company should develop, implement, and maintain a Safety Management System (SMS) which includes instructions and\nprocedures to ensure safe operation of ships and protection of the environment in compliance with relevant international and\nFlag State legislation.\nThe company should identify equipment and technical systems the sudden operational failure of which may result in hazardous\nsituations. The safety management system should provide for specific measures aimed at promoting the reliability of such\nequipment or systems. These measures should include the regular testing of standby arrangements and equipment or technical\nsystems that are not in continuous use.\n(ISM code 2018)\nDetails of the following should be included in the SMS:\n> On-board training in the operation (driving) of the gantry cranes.\n> On-board training of companion persons to guide crane drivers when attaching and landing each load.\n> A familiarisation process and associated checklist related to safe operation of the gantry cranes.\n> Safety features that can be used to stop a gantry crane in an emergency.\n> Familiarisation of new crew members and contractors with the gantry cranes.\n> Permit to work system related to the gantry cranes.\n> Precautions required when working on deck while the gantry cranes are in operation.\n> Crane-handling operation (preparation, during operation and work after crane operation)/or\n> Hatch cover lifting and travelling operation.\n> Emergency travelling operation of gantry cranes.\n> Appropriate checklists.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":176,"source_page_end":176,"raw_source_text":"Has the vessel been provided with procedures for the safe operation of the gantry crane? (V)\nGuide to Inspection\nThe inspector should randomly check the implementation of the procedures.\nEvery company should develop, implement, and maintain a Safety Management System (SMS) which includes instructions and\nprocedures to ensure safe operation of ships and protection of the environment in compliance with relevant international and\nFlag State legislation.\nThe company should identify equipment and technical systems the sudden operational failure of which may result in hazardous\nsituations. The safety management system should provide for specific measures aimed at promoting the reliability of such\nequipment or systems. These measures should include the regular testing of standby arrangements and equipment or technical\nsystems that are not in continuous use.\n(ISM code 2018)\nDetails of the following should be included in the SMS:\n> On-board training in the operation (driving) of the gantry cranes.\n> On-board training of companion persons to guide crane drivers when attaching and landing each load.\n> A familiarisation process and associated checklist related to safe operation of the gantry cranes.\n> Safety features that can be used to stop a gantry crane in an emergency.\n> Familiarisation of new crew members and contractors with the gantry cranes.\n> Permit to work system related to the gantry cranes.\n> Precautions required when working on deck while the gantry cranes are in operation.\n> Crane-handling operation (preparation, during operation and work after crane operation)/or\n> Hatch cover lifting and travelling operation.\n> Emergency travelling operation of gantry cranes.\n> Appropriate checklists.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09B","section_number":9,"section_letter":"B","section_title":"Gantry Cranes","printed_question_no":"9.2","internal_question_no":"09B.002","question_sort_key":9200200.392,"question_text":"If gantry cranes are used for lifting hatch covers, are the hydraulic cylinders used for lifting the hatch covers free from leaks and are the hatch covers being marked correctly for precise positioning of the lifting beams and hooks where applicable?","guide_to_inspection":"Record a Finding if a person rides on a hatch cover when it is being lifted by crane.\nThe hatch cover lifting devices consists of lifting frames and hydraulic cylinders. The maintenance of hydraulic cylinders shall be\nincorporated in the PMS in accordance with the manufacturer’s recommendations.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":176,"source_page_end":176,"raw_source_text":"If gantry cranes are used for lifting hatch covers, are the hydraulic cylinders used for lifting the\nhatch covers free from leaks and are the hatch covers being marked correctly for precise positioning\nof the lifting beams and hooks where applicable? (V)\nGuide to Inspection\nRecord a Finding if a person rides on a hatch cover when it is being lifted by crane.\nThe hatch cover lifting devices consists of lifting frames and hydraulic cylinders. The maintenance of hydraulic cylinders shall be\nincorporated in the PMS in accordance with the manufacturer’s recommendations.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09B","section_number":9,"section_letter":"B","section_title":"Gantry Cranes","printed_question_no":"9.3","internal_question_no":"09B.003","question_sort_key":9200300.393,"question_text":"Are check lists in place and being used to cover the check before use, starting the crane and releasing the crane from sea stowage? Is a procedure in place for safe travelling of the gantry crane on deck and are crew familiar with the procedure?","guide_to_inspection":"Trained companion persons on the ship and yard should be used to guide the crane driver when attaching and landing each load.\nPoor communication is one of the factors that contribute to the root cause of incidents related to gantry cranes.\nThere must be enough persons on each side of the deck with adequate means of communication when intending to travel the\ngantry crane. The crane operator must not start moving the crane until receiving confirmation that the crane rail is clear.\nInstallation of a track sweeper can minimise the risk of injury in event of collision.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":177,"source_page_end":177,"raw_source_text":"Are check lists in place and being used to cover the check before use, starting the crane and releasing\nthe crane from sea stowage? Is a procedure in place for safe travelling of the gantry crane on deck\nand are crew familiar with the procedure? (V)\nGuide to Inspection\nTrained companion persons on the ship and yard should be used to guide the crane driver when attaching and landing each load.\nPoor communication is one of the factors that contribute to the root cause of incidents related to gantry cranes.\nThere must be enough persons on each side of the deck with adequate means of communication when intending to travel the\ngantry crane. The crane operator must not start moving the crane until receiving confirmation that the crane rail is clear.\nInstallation of a track sweeper can minimise the risk of injury in event of collision.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09B","section_number":9,"section_letter":"B","section_title":"Gantry Cranes","printed_question_no":"9.4","internal_question_no":"09B.004","question_sort_key":9200400.394,"question_text":"Is the vessel provided with a specific isolation procedure for the gantry cranes?","guide_to_inspection":"The objectives of the ISM Code are to ensure safety at sea, prevent human injury or loss of life, and avoid damage to the\nenvironment, in particular to the marine environment, and to property. (ISM Code 2018)\nRightShip recommends that the isolation procedure should cover the need to isolate, de-energise, lockout and tag out systems,\nwith the aim of reducing the risk of death or injury during operation, inspection, repair, maintenance, and assessment of gantry\ncranes.\nThe isolation procedures shall incorporate the following:\n> Isolation procedure, check list and risk assessment documented and accessible to the relevant crew on board.\n> Information, instruction, and training provided to crew involved with the system.\n> Supervisor appointed to make sure the crew strictly follows isolation procedures.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":177,"source_page_end":177,"raw_source_text":"Is the vessel provided with a specific isolation procedure for the gantry cranes? (V)\nGuide to Inspection\nThe objectives of the ISM Code are to ensure safety at sea, prevent human injury or loss of life, and avoid damage to the\nenvironment, in particular to the marine environment, and to property. (ISM Code 2018)\nRightShip recommends that the isolation procedure should cover the need to isolate, de-energise, lockout and tag out systems,\nwith the aim of reducing the risk of death or injury during operation, inspection, repair, maintenance, and assessment of gantry\ncranes.\nThe isolation procedures shall incorporate the following:\n> Isolation procedure, check list and risk assessment documented and accessible to the relevant crew on board.\n> Information, instruction, and training provided to crew involved with the system.\n> Supervisor appointed to make sure the crew strictly follows isolation procedures.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09B","section_number":9,"section_letter":"B","section_title":"Gantry Cranes","printed_question_no":"9.5","internal_question_no":"09B.005","question_sort_key":9200500.395,"question_text":"Are the visual and audible warning signals provided for gantry cranes in the deck area in good order and tested regularly?","guide_to_inspection":"Locating the alarm bell near the wheels reduces the risk of collision, as it makes it easier to hear the alarm at the point of danger. All\nnecessary warning signs shall be located on the crane legs.\nGantry cranes must be fitted with an acoustic warning device, such as horn that can be sounded by the crane operator, that:\n(i) emits an audible sound before travelling motion is commenced; and\n(ii) continues to sound until travelling motion has ceased.\n(Marine Order 32 (Cargo handling equipment) 2016, 2017)\nGantry cranes and similar cranes shall be provided with a horn or other audible warning device operated by the crane operator to\nwarn or attract the attention of any personnel within the operational area.\nIn case of travelling cranes moving at ground level, a continuous audible warning shall automatically be given when the crane is to\nmove/is moving along the track/rails. The warning signal shall be distinctly different from other audio signals on the installation.\n(Code for Lifting Appliances in a Marine Environment, 2009)\nTo alert personnel of gantry movement, the crane shall be equipped with four flashlights and warning bells mounted at each corner\nof the gantry. A signal horn operated from the driver’s cab shall be provided. Red indicator lights shall be fitted on the extremes of\nthe jibs and be automatically actuated when the jibs are in operation position.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":177,"source_page_end":177,"raw_source_text":"Are the visual and audible warning signals provided for gantry cranes in the deck area in good\norder and tested regularly? (V)\nGuide to Inspection\nLocating the alarm bell near the wheels reduces the risk of collision, as it makes it easier to hear the alarm at the point of danger. All\nnecessary warning signs shall be located on the crane legs.\nGantry cranes must be fitted with an acoustic warning device, such as horn that can be sounded by the crane operator, that:\n(i) emits an audible sound before travelling motion is commenced; and\n(ii) continues to sound until travelling motion has ceased.\n(Marine Order 32 (Cargo handling equipment) 2016, 2017)\nGantry cranes and similar cranes shall be provided with a horn or other audible warning device operated by the crane operator to\nwarn or attract the attention of any personnel within the operational area.\nIn case of travelling cranes moving at ground level, a continuous audible warning shall automatically be given when the crane is to\nmove/is moving along the track/rails. The warning signal shall be distinctly different from other audio signals on the installation.\n(Code for Lifting Appliances in a Marine Environment, 2009)\nTo alert personnel of gantry movement, the crane shall be equipped with four flashlights and warning bells mounted at each corner\nof the gantry. A signal horn operated from the driver’s cab shall be provided. Red indicator lights shall be fitted on the extremes of\nthe jibs and be automatically actuated when the jibs are in operation position.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09B","section_number":9,"section_letter":"B","section_title":"Gantry Cranes","printed_question_no":"9.6","internal_question_no":"09B.006","question_sort_key":9200600.396,"question_text":"Are the safety devices of gantry cranes in good order and is there recorded evidences of regular testing?","guide_to_inspection":"A list of safety devices shall be incorporated in the PMS and maintenance intervals as per manufacturer’s recommendation shall\nbe followed. The inspector should verify whether these tests have been included within the PMS.\nCrane emergency stop pushbuttons/trip wires: The emergency stops should be located at all control positions and local panels\naround the cranes, clearly marked to indicate the crane they serve, and within easy reach.\nCow catchers: The cow catchers are mechanical switches mounted on each corner of the gantry operated by a collision bar\nmechanism.\nEnd stop limit switches: Each gantry has hardwired slow down and end stop limits at both sides of its movement range.\nHoist, trolley and shift trolley movements have software limit switches called smart slow down. Hardwired end stop limits are\nactivated only in fault situations.\nThe over hoisting/lowering end stop limit switches will activate if the main hoist would rise/lower over its normal stop position.\nMain trolley traversing and shift trolley shifting end stop limit are rotating limit switches mounted on the machinery.\nGantry travelling has a rotating limit switch, after crane backward direction has also proximity limit switch as end position.\nOverspeed protection: The main hoist, main trolley traversing and gantry travelling motions are protected against overspeed\nduring operation.\nA gantry crane shall be fitted with a clearly labelled emergency stop switch that can easily be operated by persons at deck level.\n(Marine Order 32 (Cargo handling equipment) 2016, 2017)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":178,"source_page_end":178,"raw_source_text":"Are the safety devices of gantry cranes in good order and is there recorded evidences of regular testing? (V)\nGuide to Inspection\nA list of safety devices shall be incorporated in the PMS and maintenance intervals as per manufacturer’s recommendation shall\nbe followed. The inspector should verify whether these tests have been included within the PMS.\nCrane emergency stop pushbuttons/trip wires: The emergency stops should be located at all control positions and local panels\naround the cranes, clearly marked to indicate the crane they serve, and within easy reach.\nCow catchers: The cow catchers are mechanical switches mounted on each corner of the gantry operated by a collision bar\nmechanism.\nEnd stop limit switches: Each gantry has hardwired slow down and end stop limits at both sides of its movement range.\nHoist, trolley and shift trolley movements have software limit switches called smart slow down. Hardwired end stop limits are\nactivated only in fault situations.\nThe over hoisting/lowering end stop limit switches will activate if the main hoist would rise/lower over its normal stop position.\nMain trolley traversing and shift trolley shifting end stop limit are rotating limit switches mounted on the machinery.\nGantry travelling has a rotating limit switch, after crane backward direction has also proximity limit switch as end position.\nOverspeed protection: The main hoist, main trolley traversing and gantry travelling motions are protected against overspeed\nduring operation.\nA gantry crane shall be fitted with a clearly labelled emergency stop switch that can easily be operated by persons at deck level.\n(Marine Order 32 (Cargo handling equipment) 2016, 2017)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09B","section_number":9,"section_letter":"B","section_title":"Gantry Cranes","printed_question_no":"9.7","internal_question_no":"09B.007","question_sort_key":9200700.397,"question_text":"Are the main hoist overload protection and unbalance detection systems in good order and tested as per manufacturer’s recommendation? Are officers aware of the safe operation parameters of gantry cranes and is this information posted in the ship’s office/ ballast control room?","guide_to_inspection":"The ship’s condition during load handling, hatch cover lifting, jib turning and crane sea stowing as well as the wind speed during\ncrane operation shall be posted in the ship’s office/ballast control room.\nThe overload protection is designed to prevent lifting loads that exceeds the lifting capacity of the crane. The Chief Officer shall\nbe aware of the maximum load that the main hoist can load at all possible places and the heaviest load that must be loaded at\nthe centre position. This information shall be posted in the cargo control room.\nThe load unbalance detection system shall prevent movement of eccentric loads.\nDuring storm wind events, the gantry cranes and their associated structures are exposed to loading which may not have been\nconsidered in the design and construction or during the operation of the crane. Crew should be familiar with and understand the\ndesign/operating limitations of the gantry cranes with regards to wind speed criteria.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":178,"source_page_end":178,"raw_source_text":"Are the main hoist overload protection and unbalance detection systems in good order and tested\nas per manufacturer’s recommendation? Are officers aware of the safe operation parameters of\ngantry cranes and is this information posted in the ship’s office/ ballast control room? (V)\nGuide to Inspection\nThe ship’s condition during load handling, hatch cover lifting, jib turning and crane sea stowing as well as the wind speed during\ncrane operation shall be posted in the ship’s office/ballast control room.\nThe overload protection is designed to prevent lifting loads that exceeds the lifting capacity of the crane. The Chief Officer shall\nbe aware of the maximum load that the main hoist can load at all possible places and the heaviest load that must be loaded at\nthe centre position. This information shall be posted in the cargo control room.\nThe load unbalance detection system shall prevent movement of eccentric loads.\nDuring storm wind events, the gantry cranes and their associated structures are exposed to loading which may not have been\nconsidered in the design and construction or during the operation of the crane. Crew should be familiar with and understand the\ndesign/operating limitations of the gantry cranes with regards to wind speed criteria.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09B","section_number":9,"section_letter":"B","section_title":"Gantry Cranes","printed_question_no":"9.8","internal_question_no":"09B.008","question_sort_key":9200800.398,"question_text":"Is each gantry cranes provided with a storm locking arrangement and, does the arrangement appeared to be well maintained?","guide_to_inspection":"The gantry cranes shall be fitted with devices that lock the crane in position when exposed to wind pressure.\n(Marine Order 32 (Cargo handling equipment) 2016, 2017)\nIf a hydraulically operated locking system has been provided, the components of the system, i.e., hydraulic cylinder actuation\nand hydraulic hoses, shall be in good condition and the system shall be free of oil leaks.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":178,"source_page_end":178,"raw_source_text":"Is each gantry cranes provided with a storm locking arrangement and, does the arrangement\nappeared to be well maintained? (V)\nGuide to Inspection\nThe gantry cranes shall be fitted with devices that lock the crane in position when exposed to wind pressure.\n(Marine Order 32 (Cargo handling equipment) 2016, 2017)\nIf a hydraulically operated locking system has been provided, the components of the system, i.e., hydraulic cylinder actuation\nand hydraulic hoses, shall be in good condition and the system shall be free of oil leaks.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09B","section_number":9,"section_letter":"B","section_title":"Gantry Cranes","printed_question_no":"9.9","internal_question_no":"09B.009","question_sort_key":9200900.399,"question_text":"Are the gantry cranes electrically bonded and earthed to the vessel’s structure?","guide_to_inspection":"A bridge or gantry crane used in loading or unloading must be electrically bonded and earthed to the vessel’s structure.\n(Marine Order 32 (Cargo handling equipment) 2016, 2017)\nANSI/NFPA 70 National Electric Code within Article 610, Cranes and Hoists, section 610.61:” The trolley frame and bridge frame\nshall not be considered electrically grounded through the bridge and trolley wheels and its respective tracks. A separate bonding\nconductor shall be provided.”","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":179,"source_page_end":179,"raw_source_text":"Are the gantry cranes electrically bonded and earthed to the vessel’s structure? (V)\nGuide to Inspection\nA bridge or gantry crane used in loading or unloading must be electrically bonded and earthed to the vessel’s structure.\n(Marine Order 32 (Cargo handling equipment) 2016, 2017)\nANSI/NFPA 70 National Electric Code within Article 610, Cranes and Hoists, section 610.61:” The trolley frame and bridge frame\nshall not be considered electrically grounded through the bridge and trolley wheels and its respective tracks. A separate bonding\nconductor shall be provided.”","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09B","section_number":9,"section_letter":"B","section_title":"Gantry Cranes","printed_question_no":"9.10","internal_question_no":"09B.010","question_sort_key":9201000.4,"question_text":"Are the mechanical brakes for the gantry crane motions in good order, tested regularly, and recorded?","guide_to_inspection":"Mechanical brakes for the crane movements are primarily designed as holding brakes. Deceleration forces are normally\nprovided by the electrical braking of the drive motors. During an emergency stop, the mechanical brakes are engaged\nimmediately, but without the deceleration force from the motor. The condition of the brake linings should be checked regularly.\nProcedures for checking the air gap and the thickness of the brakes’ lining materials should be incorporated in the PMS as per\nmanufacturer’s recommendation.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":179,"source_page_end":179,"raw_source_text":"Are the mechanical brakes for the gantry crane motions in good order, tested regularly, and recorded? (V)\nGuide to Inspection\nMechanical brakes for the crane movements are primarily designed as holding brakes. Deceleration forces are normally\nprovided by the electrical braking of the drive motors. During an emergency stop, the mechanical brakes are engaged\nimmediately, but without the deceleration force from the motor. The condition of the brake linings should be checked regularly.\nProcedures for checking the air gap and the thickness of the brakes’ lining materials should be incorporated in the PMS as per\nmanufacturer’s recommendation.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09B","section_number":9,"section_letter":"B","section_title":"Gantry Cranes","printed_question_no":"9.11","internal_question_no":"09B.011","question_sort_key":9201100.401,"question_text":"Are the anti-collision and deceleration devices of the gantry cranes in good order and tested regularly, and are track wheels at the deck level fitted with foot guards?","guide_to_inspection":"If there is more than one crane on the same trackway — each must be fitted with a device to prevent collision. Any track wheels\nat deck level shall be fitted with foot guards.\n(Marine Order 32 (Cargo handling equipment) 2016, 2017)\nThe Anti-collision system will stop the cranes if the fore crane and aft crane would come too close each other.\nDeceleration devices, such as limit switches and two-stage decelerators, slow the gantry crane down regardless of what control\nis being pressed when a travelling crane is approaching the end of the runway, to prevent end stop collision or overrun.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":179,"source_page_end":179,"raw_source_text":"Are the anti-collision and deceleration devices of the gantry cranes in good order and tested\nregularly, and are track wheels at the deck level fitted with foot guards? (V)\nGuide to Inspection\nIf there is more than one crane on the same trackway — each must be fitted with a device to prevent collision. Any track wheels\nat deck level shall be fitted with foot guards.\n(Marine Order 32 (Cargo handling equipment) 2016, 2017)\nThe Anti-collision system will stop the cranes if the fore crane and aft crane would come too close each other.\nDeceleration devices, such as limit switches and two-stage decelerators, slow the gantry crane down regardless of what control\nis being pressed when a travelling crane is approaching the end of the runway, to prevent end stop collision or overrun.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09B","section_number":9,"section_letter":"B","section_title":"Gantry Cranes","printed_question_no":"9.12","internal_question_no":"09B.012","question_sort_key":9201200.402,"question_text":"If the operator’s cabin of a gantry crane travels with the horizontal movement of a load, is the crane operator able to leave the cabin safely in case of power failure or another emergency?","guide_to_inspection":"If the operator’s cabin of a track-mounted crane travels with the horizontal movement of a load, the structure must enable the operator\nto leave the cabin safely if there is a power failure or other emergency.\nExample of an appropriate structure: A mobile or portable access or means of returning the cabin from the track to the point of access.\n(Marine Order 32 (Cargo handling equipment) 2016, 2017)\nThe emergency escape routes shall be clearly marked.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":179,"source_page_end":179,"raw_source_text":"If the operator’s cabin of a gantry crane travels with the horizontal movement of a load, is the\ncrane operator able to leave the cabin safely in case of power failure or another emergency? (V)\nGuide to Inspection\nIf the operator’s cabin of a track-mounted crane travels with the horizontal movement of a load, the structure must enable the operator\nto leave the cabin safely if there is a power failure or other emergency.\nExample of an appropriate structure: A mobile or portable access or means of returning the cabin from the track to the point of access.\n(Marine Order 32 (Cargo handling equipment) 2016, 2017)\nThe emergency escape routes shall be clearly marked.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09B","section_number":9,"section_letter":"B","section_title":"Gantry Cranes","printed_question_no":"9.13","internal_question_no":"09B.013","question_sort_key":9201300.403,"question_text":"Are portable fire extinguishers located around the gantry cranes and in good condition, and are they maintained regularly?","guide_to_inspection":"","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"not_provided","source_page_start":179,"source_page_end":179,"raw_source_text":"Are portable fire extinguishers located around the gantry cranes and in good condition, and are\nthey maintained regularly? (V)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09B","section_number":9,"section_letter":"B","section_title":"Gantry Cranes","printed_question_no":"9.14","internal_question_no":"09B.014","question_sort_key":9201400.404,"question_text":"Are the driver’s cabs and local operating stations of the gantry cranes maintained in good condition?","guide_to_inspection":"The cabin panel shall be labelled, and the function lights shall be in working condition. The window wiper, window’s glass and\ndriver’s chair should be maintained in good condition.\nThe local operating stations are used for the purpose of the gantry drive, hatch cover and JIB operation.\nThe switches, instruments such as controllers, telephone, microphone, speaker, heater, air-conditioner, electric window wiper,\nfire extinguisher, rotating chair and cabin’s lights should be in good condition. The maintenance of driver’s cab should be\nincorporated into the PMS.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":180,"source_page_end":180,"raw_source_text":"Are the driver’s cabs and local operating stations of the gantry cranes maintained in good condition? (V)\nGuide to Inspection\nThe cabin panel shall be labelled, and the function lights shall be in working condition. The window wiper, window’s glass and\ndriver’s chair should be maintained in good condition.\nThe local operating stations are used for the purpose of the gantry drive, hatch cover and JIB operation.\nThe switches, instruments such as controllers, telephone, microphone, speaker, heater, air-conditioner, electric window wiper,\nfire extinguisher, rotating chair and cabin’s lights should be in good condition. The maintenance of driver’s cab should be\nincorporated into the PMS.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09B","section_number":9,"section_letter":"B","section_title":"Gantry Cranes","printed_question_no":"9.15","internal_question_no":"09B.015","question_sort_key":9201500.405,"question_text":"Are the retractable jib roofs, sides’ curtains and their securing arrangement being maintained in good condition, are checklists for the operation of the jib roof and curtains available and is the evidence of their consistent use?","guide_to_inspection":"The jib roof end limit switches and emergency stop pushbutton shall be function tested regularly and evidence of such tests\nshall be recorded.\nThe gantry cranes are fitted with retractable roofs, which cover the whole working area including the outreach area which\nenables operation in unfavourable weather. Some vessels are also equipped with curtains on the sides that enable work in the\nevent of most adverse weather conditions. The side curtains are roller mounted horizontally on the outside of the main girders.\nAt the bottom, the curtains are equipped with counterweights and supported by the girder.\nThe jib roofs’ locking arrangements shall be maintained in good condition.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":180,"source_page_end":180,"raw_source_text":"Are the retractable jib roofs, sides’ curtains and their securing arrangement being maintained in\ngood condition, are checklists for the operation of the jib roof and curtains available and is the\nevidence of their consistent use? (V)\nGuide to Inspection\nThe jib roof end limit switches and emergency stop pushbutton shall be function tested regularly and evidence of such tests\nshall be recorded.\nThe gantry cranes are fitted with retractable roofs, which cover the whole working area including the outreach area which\nenables operation in unfavourable weather. Some vessels are also equipped with curtains on the sides that enable work in the\nevent of most adverse weather conditions. The side curtains are roller mounted horizontally on the outside of the main girders.\nAt the bottom, the curtains are equipped with counterweights and supported by the girder.\nThe jib roofs’ locking arrangements shall be maintained in good condition.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09B","section_number":9,"section_letter":"B","section_title":"Gantry Cranes","printed_question_no":"9.16","internal_question_no":"09B.016","question_sort_key":9201600.406,"question_text":"Is the telephone system provided for communication between driver’s cab, electrical control room, hatch cover control station and deck level in good order and is there evidence of regular testing and maintenance?","guide_to_inspection":"The following considerations should be taken into account if radios are to be used as a means of communication:\n> The radio should be tested prior to use to ensure clear and reliable transmission.\n> The crane should use a separate working channel, if possible, and if frequencies are available.\n> The crane cab operator’s radio should be equipped with a hands-free system.\n> Radios should not be used for personal communication or discussions unrelated to the crane operation at hand.\n> Ensure that the crane operator and crew communicating with the crane operator are trained in the proper use of the radio\nequipment.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":180,"source_page_end":180,"raw_source_text":"Is the telephone system provided for communication between driver’s cab, electrical control room,\nhatch cover control station and deck level in good order and is there evidence of regular testing\nand maintenance? (V)\nGuide to Inspection\nThe following considerations should be taken into account if radios are to be used as a means of communication:\n> The radio should be tested prior to use to ensure clear and reliable transmission.\n> The crane should use a separate working channel, if possible, and if frequencies are available.\n> The crane cab operator’s radio should be equipped with a hands-free system.\n> Radios should not be used for personal communication or discussions unrelated to the crane operation at hand.\n> Ensure that the crane operator and crew communicating with the crane operator are trained in the proper use of the radio\nequipment.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09B","section_number":9,"section_letter":"B","section_title":"Gantry Cranes","printed_question_no":"9.17","internal_question_no":"09B.017","question_sort_key":9201700.407,"question_text":"If a platform has been provided on the top of the crane roof for helicopter winching operations, does the area comply with the requirements of ICS guidelines?","guide_to_inspection":"The positioning and marking of the winching operations shall comply with the requirement of section 4.4.1 and 4.4.3 of the\nGuide to Helicopter/Ship Operations.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":180,"source_page_end":180,"raw_source_text":"If a platform has been provided on the top of the crane roof for helicopter winching operations,\ndoes the area comply with the requirements of ICS guidelines? (V)\nGuide to Inspection\nThe positioning and marking of the winching operations shall comply with the requirement of section 4.4.1 and 4.4.3 of the\nGuide to Helicopter/Ship Operations.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09B","section_number":9,"section_letter":"B","section_title":"Gantry Cranes","printed_question_no":"9.18","internal_question_no":"09B.018","question_sort_key":9201800.408,"question_text":"If the gantry crane is equipped with a pilot ladder hoist, is the system being by-passed and not in use?","guide_to_inspection":"In December 2010 IMO MSC 88 adopted MSC.308(88), which contains amendments to SOLAS regulation V/23 and IMO\nresolution A.1045(27). This amendment provides additional recommendations for pilot ladder arrangements and pilot transfer\narrangements. Amendments and changes to SOLAS chapter V/23 and IMO Resolution A.1045(27) have banned the use of\nmechanical pilot hoists.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":180,"source_page_end":180,"raw_source_text":"If the gantry crane is equipped with a pilot ladder hoist, is the system being by-passed and not in use? (V)\nGuide to Inspection\nIn December 2010 IMO MSC 88 adopted MSC.308(88), which contains amendments to SOLAS regulation V/23 and IMO\nresolution A.1045(27). This amendment provides additional recommendations for pilot ladder arrangements and pilot transfer\narrangements. Amendments and changes to SOLAS chapter V/23 and IMO Resolution A.1045(27) have banned the use of\nmechanical pilot hoists.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09B","section_number":9,"section_letter":"B","section_title":"Gantry Cranes","printed_question_no":"9.19","internal_question_no":"09B.019","question_sort_key":9201900.409,"question_text":"Have a Crane Monitoring System and a port/crane performance logger been provided, are they in good condition and regularly monitored? Are faults recorded in the fault log, verified and fault-finding rectification procedures recorded appropriately?","guide_to_inspection":"The Crane Monitoring System gives more detailed information about faults. All defects must be repaired before the crane is\ntaken back into operation.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":181,"source_page_end":181,"raw_source_text":"Have a Crane Monitoring System and a port/crane performance logger been provided, are they\nin good condition and regularly monitored? Are faults recorded in the fault log, verified and\nfault-finding rectification procedures recorded appropriately? (V)\nGuide to Inspection\nThe Crane Monitoring System gives more detailed information about faults. All defects must be repaired before the crane is\ntaken back into operation.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09B","section_number":9,"section_letter":"B","section_title":"Gantry Cranes","printed_question_no":"9.20","internal_question_no":"09B.020","question_sort_key":9202000.41,"question_text":"Is the emergency pump for the operation of the crane maintained in good condition, are crew familiar with their duties in the using the emergency pump and are emergency drills being carried out?","guide_to_inspection":"The crane is equipped with an emergency pump that can be used instead of the main hydraulic pumps. In case of electric fault,\ndriving of hydraulic cylinders with a manually controlled valve is possible. However, the person operating the manual controlled\nvalve will not be able to see the crane’s operation clearly enough. To prevent accidents there must be an assistant(s) observing\nthe motion of the hydraulic cylinders and all working parts. The assistant(s) must have phone communication with the person\noperating the emergency pump.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":181,"source_page_end":181,"raw_source_text":"Is the emergency pump for the operation of the crane maintained in good condition, are crew\nfamiliar with their duties in the using the emergency pump and are emergency drills being carried out? (V)\nGuide to Inspection\nThe crane is equipped with an emergency pump that can be used instead of the main hydraulic pumps. In case of electric fault,\ndriving of hydraulic cylinders with a manually controlled valve is possible. However, the person operating the manual controlled\nvalve will not be able to see the crane’s operation clearly enough. To prevent accidents there must be an assistant(s) observing\nthe motion of the hydraulic cylinders and all working parts. The assistant(s) must have phone communication with the person\noperating the emergency pump.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09B","section_number":9,"section_letter":"B","section_title":"Gantry Cranes","printed_question_no":"9.21","internal_question_no":"09B.021","question_sort_key":9202100.411,"question_text":"Is the steel structure of girders and trolleys free of deformation? Are the access and service platforms of the gantry cranes, including vertical ladders, ladders cages, rungs, stations and platforms being maintained, free of corrosion and in good order?","guide_to_inspection":"Random checks of following should be made by inspector to ensure that the gantry crane is free of apparent structural defects.\n> Cracks in the welds,\n> Deformed structural members,\n> Any negative camber in the bridge beam,\n> Operational damage due to collision with another crane,\n> Excessive structural corrosion","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":181,"source_page_end":181,"raw_source_text":"Is the steel structure of girders and trolleys free of deformation? Are the access and service\nplatforms of the gantry cranes, including vertical ladders, ladders cages, rungs, stations and\nplatforms being maintained, free of corrosion and in good order? (V)\nGuide to Inspection\nRandom checks of following should be made by inspector to ensure that the gantry crane is free of apparent structural defects.\n> Cracks in the welds,\n> Deformed structural members,\n> Any negative camber in the bridge beam,\n> Operational damage due to collision with another crane,\n> Excessive structural corrosion","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09B","section_number":9,"section_letter":"B","section_title":"Gantry Cranes","printed_question_no":"9.22","internal_question_no":"09B.022","question_sort_key":9202200.412,"question_text":"Are the cranes’ transverse rail, rack, tooth-rack, travelling pinion and travelling wheel free of cracks, misalignment, and abnormal wear; and is there evidence of regular inspection and maintenance?","guide_to_inspection":"Parts of a crane are subject to wear by operation and deformation due to vibration. If wearing or deformation of any part have\nreached the prescribed limit, the part must be renewed. This limit is called the wearing limit. A procedure shall be in place\nfor measuring the wear and comparing the measurements with the manufacturer’s recommendation. The inspector should\nrandomly check whether the wearing of parts is within the acceptable limit, as recommended by the manufacturer.\nThe travelling rail and rack shall be free of 1- obstructions on the rail, 2-cracks, 3-damage of the rail brackets, 4-deformation of\nthe rail and 5-have adequate clearance at rail joint, as per manufacturer’s recommendation.\nThe travelling wheel shall run smoothly without any abnormality in bearing revolution, free from 1-abnormal wearing on the\nwheel surface, 2-cracks, and 3- the fitting bolts should be tightened.\nThe travelling pinion shall be free of 1-cracks, 2-abnormal wearing or pitching and 3-abnormal engaging with travelling rack.\nThe gear boxes’ oil level shall be maintained at normal level.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":181,"source_page_end":181,"raw_source_text":"Are the cranes’ transverse rail, rack, tooth-rack, travelling pinion and travelling wheel free of cracks,\nmisalignment, and abnormal wear; and is there evidence of regular inspection and maintenance? (V)\nGuide to Inspection\nParts of a crane are subject to wear by operation and deformation due to vibration. If wearing or deformation of any part have\nreached the prescribed limit, the part must be renewed. This limit is called the wearing limit. A procedure shall be in place\nfor measuring the wear and comparing the measurements with the manufacturer’s recommendation. The inspector should\nrandomly check whether the wearing of parts is within the acceptable limit, as recommended by the manufacturer.\nThe travelling rail and rack shall be free of 1- obstructions on the rail, 2-cracks, 3-damage of the rail brackets, 4-deformation of\nthe rail and 5-have adequate clearance at rail joint, as per manufacturer’s recommendation.\nThe travelling wheel shall run smoothly without any abnormality in bearing revolution, free from 1-abnormal wearing on the\nwheel surface, 2-cracks, and 3- the fitting bolts should be tightened.\nThe travelling pinion shall be free of 1-cracks, 2-abnormal wearing or pitching and 3-abnormal engaging with travelling rack.\nThe gear boxes’ oil level shall be maintained at normal level.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09B","section_number":9,"section_letter":"B","section_title":"Gantry Cranes","printed_question_no":"9.23","internal_question_no":"09B.023","question_sort_key":9202300.413,"question_text":"Is there evidence to show that regular maintenance has been conducted on the AC motors, electromechanical brake, gear reducer and the blower motors?","guide_to_inspection":"The inspector shall check if the maintenance of main hoist machinery, turntable slewing machinery, shift-trolley shifting\nmachinery, main trolley traversing machinery, gantry travelling machinery and hydraulic unit are incorporated in the PMS and\nbeing carried out as per manufacturer’s recommendation.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":182,"source_page_end":182,"raw_source_text":"Is there evidence to show that regular maintenance has been conducted on the AC motors,\nelectromechanical brake, gear reducer and the blower motors? (V)\nGuide to Inspection\nThe inspector shall check if the maintenance of main hoist machinery, turntable slewing machinery, shift-trolley shifting\nmachinery, main trolley traversing machinery, gantry travelling machinery and hydraulic unit are incorporated in the PMS and\nbeing carried out as per manufacturer’s recommendation.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"09B","section_number":9,"section_letter":"B","section_title":"Gantry Cranes","printed_question_no":"9.24","internal_question_no":"09B.024","question_sort_key":9202400.414,"question_text":"Has the hydraulic oil of the gantry crane system been tested regularly for contamination and deterioration as per manufacturer recommendation?","guide_to_inspection":"Monitoring hydraulics with oil analysis is the only way to establish whether the hydraulic fluid is impacting the anticipated\nperformance. Contamination is the main cause of failure, typically water contamination or dirt ingression.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":182,"source_page_end":182,"raw_source_text":"Has the hydraulic oil of the gantry crane system been tested regularly for contamination and\ndeterioration as per manufacturer recommendation? (V)\nGuide to Inspection\nMonitoring hydraulics with oil analysis is the only way to establish whether the hydraulic fluid is impacting the anticipated\nperformance. Contamination is the main cause of failure, typically water contamination or dirt ingression.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"10A","section_number":10,"section_letter":"A","section_title":"Mooring Operations","printed_question_no":"10.1","internal_question_no":"10A.001","question_sort_key":10100100.415,"question_text":"Has the company established guidelines and procedures for the inspection, maintenance and wear zone management of the mooring lines and are they being implemented?","guide_to_inspection":"The inspector shall conduct random checks on the ship’s mooring line management plan against Section 2 of INTERTANKO’s\nGuidance on Line Management Plans. Click here to download the INTERTANKO guideline.\nRecord a Finding if the ship’s Mooring Line Management Plan does not meet the requirements of section 2 of the INTERTANKO\nguideline.\nRecord a Finding, if there is no evidence that the Line Management Plan is being implemented on board the ship.\nLine Management Plan (LMP) is used to manage the operation and retirement of mooring lines and tails. The LMP also\ndocuments the requirements, assumptions and evaluation methods used in determining the line retirement criteria. The LMP\nis specific to a vessel’s manager, ship type, and trade route; however, Oil Companies International Maritime Forum (OCIMF) has\ngiven general guidance on establishing a LMP in the Mooring Equipment Guideline Edition 4(MEG4).\nThe vessel’s manager is responsible for the development and implementation of the ships Line Management Plan (LMP).\nThe LMP will contain the vessel’s manager requirement for the management of mooring line maintenance, inspection, and\nretirement during the operational phase of the mooring line lifecycle.\nThe LMP can be a standalone tool, or it may be integrated into existing safety or maintenance management systems. It can be\navailable as hard or electronic copy, or both. Whatever the format, the LMP should be capable of being updated. It should be\naccessible for internal and external compliance verification, ship personnel training and communication with manufacturers.\nLMP information should be stored in a location that is easy for all users to access, e.g., on a computer system that can be\naccessed from both the ship and shore or compiled in a single physical location. It should be easy for the system users to\naccess the LMP information from a single physical or virtual location.\nTable 5.2 of the Mooring Equipment Guideline (MEG4) gives an overview of the type of information that could be included in the\nLMP for maintenance, inspection, and retirement, as well as general considerations that apply to the safe use and maintenance\nof mooring lines. Operators can use the table as a starting point for the development of their LMP but should recognise that this\nlist it is not considered exhaustive.\nAll types of mooring lines experience localised fatigue and damage caused by common line routeing and deployment\nprocesses. The location and extent of localised damage on the mooring line can vary due to various factors, i.e., trading patterns,\nberth layout and design, mooring pendent length and material, ship’s movements while at the port, environmental condition, and\nladen and ballast ship.\nThe wear zone management should be incorporated in the LMP. Section 5.4.4 of MEG4 has provided further guidance about the\nwear zone management.\n(Mooring Equipment Guidelines (MEG4), 2018)\nConventional fibre lines: At routine intervals, the entire length of line should be inspected by a competent person*. Attention\nshould be paid to those sections of line that are proven by experience to be the main areas of deterioration, such as spliced\neyes and interface area with winches, capstans, bollards, fairleads, and rollers. In the absence of sufficiently detailed inspection\nprocesses from the line manufacturer, the vessel’s manager should refer to the Cordage Institute guideline, “Fiber Rope\nInspection and Retirement Criteria – The Guideline that can Provide Enhanced Fiber Rope Durability and Important Information\nfor the Safer Use of Fiber Rope”.\n(Mooring Equipment Guidelines (MEG4), 2018)\n*Personnel assigned the responsibility for rope inspections should be properly trained to recognise rope damage and to\nunderstand the rope inspection procedures and retirement criteria.\nEvery vessel shall have a minimum of two spare mooring lines available and ready for immediate use.\n(33 CFR 401.12)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V & M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":183,"source_page_end":183,"raw_source_text":"Has the company established guidelines and procedures for the inspection, maintenance and\nwear zone management of the mooring lines and are they being implemented? (V & M)\nGuide to Inspection\nThe inspector shall conduct random checks on the ship’s mooring line management plan against Section 2 of INTERTANKO’s\nGuidance on Line Management Plans. Click here to download the INTERTANKO guideline.\nRecord a Finding if the ship’s Mooring Line Management Plan does not meet the requirements of section 2 of the INTERTANKO\nguideline.\nRecord a Finding, if there is no evidence that the Line Management Plan is being implemented on board the ship.\nLine Management Plan (LMP) is used to manage the operation and retirement of mooring lines and tails. The LMP also\ndocuments the requirements, assumptions and evaluation methods used in determining the line retirement criteria. The LMP\nis specific to a vessel’s manager, ship type, and trade route; however, Oil Companies International Maritime Forum (OCIMF) has\ngiven general guidance on establishing a LMP in the Mooring Equipment Guideline Edition 4(MEG4).\nThe vessel’s manager is responsible for the development and implementation of the ships Line Management Plan (LMP).\nThe LMP will contain the vessel’s manager requirement for the management of mooring line maintenance, inspection, and\nretirement during the operational phase of the mooring line lifecycle.\nThe LMP can be a standalone tool, or it may be integrated into existing safety or maintenance management systems. It can be\navailable as hard or electronic copy, or both. Whatever the format, the LMP should be capable of being updated. It should be\naccessible for internal and external compliance verification, ship personnel training and communication with manufacturers.\nLMP information should be stored in a location that is easy for all users to access, e.g., on a computer system that can be\naccessed from both the ship and shore or compiled in a single physical location. It should be easy for the system users to\naccess the LMP information from a single physical or virtual location.\nTable 5.2 of the Mooring Equipment Guideline (MEG4) gives an overview of the type of information that could be included in the\nLMP for maintenance, inspection, and retirement, as well as general considerations that apply to the safe use and maintenance\nof mooring lines. Operators can use the table as a starting point for the development of their LMP but should recognise that this\nlist it is not considered exhaustive.\nAll types of mooring lines experience localised fatigue and damage caused by common line routeing and deployment\nprocesses. The location and extent of localised damage on the mooring line can vary due to various factors, i.e., trading patterns,\nberth layout and design, mooring pendent length and material, ship’s movements while at the port, environmental condition, and\nladen and ballast ship.\nThe wear zone management should be incorporated in the LMP. Section 5.4.4 of MEG4 has provided further guidance about the\nwear zone management.\n(Mooring Equipment Guidelines (MEG4), 2018)\nConventional fibre lines: At routine intervals, the entire length of line should be inspected by a competent person*. Attention\nshould be paid to those sections of line that are proven by experience to be the main areas of deterioration, such as spliced\neyes and interface area with winches, capstans, bollards, fairleads, and rollers. In the absence of sufficiently detailed inspection\nprocesses from the line manufacturer, the vessel’s manager should refer to the Cordage Institute guideline, “Fiber Rope\nInspection and Retirement Criteria – The Guideline that can Provide Enhanced Fiber Rope Durability and Important Information\nfor the Safer Use of Fiber Rope”.\n(Mooring Equipment Guidelines (MEG4), 2018)\n*Personnel assigned the responsibility for rope inspections should be properly trained to recognise rope damage and to\nunderstand the rope inspection procedures and retirement criteria.\nEvery vessel shall have a minimum of two spare mooring lines available and ready for immediate use.\n(33 CFR 401.12)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"10A","section_number":10,"section_letter":"A","section_title":"Mooring Operations","printed_question_no":"10.2","internal_question_no":"10A.002","question_sort_key":10100200.416,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":183,"source_page_end":183,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}}]}$RISQQ111$::jsonb AS payload
),
qs AS (
  SELECT id AS question_set_id FROM public.risq_question_sets WHERE question_set_code = 'RISQ_3_2' LIMIT 1
),
input_rows AS (
  SELECT *
  FROM payload p
  CROSS JOIN LATERAL jsonb_to_recordset(p.payload->'questions') AS r(
    section_code text,
    section_number integer,
    section_letter text,
    section_title text,
    printed_question_no text,
    internal_question_no text,
    question_sort_key numeric,
    question_text text,
    guide_to_inspection text,
    answer_type text,
    answer_options jsonb,
    answer_options_inferred boolean,
    inspection_marker text,
    is_removed_question boolean,
    is_active boolean,
    guide_status text,
    source_page_start integer,
    source_page_end integer,
    raw_source_text text,
    metadata jsonb
  )
),
section_lookup AS (
  SELECT s.id AS section_id, s.question_set_id, s.section_code
  FROM public.risq_sections s
  JOIN qs ON qs.question_set_id = s.question_set_id
)
INSERT INTO public.risq_questions (
  question_set_id,
  section_id,
  section_code,
  section_number,
  section_letter,
  section_title,
  printed_question_no,
  internal_question_no,
  question_sort_key,
  question_text,
  guide_to_inspection,
  answer_type,
  answer_options,
  answer_options_inferred,
  inspection_marker,
  is_removed_question,
  is_active,
  guide_status,
  source_page_start,
  source_page_end,
  raw_source_text,
  source_hash,
  metadata,
  created_by,
  updated_by
)
SELECT
  qs.question_set_id,
  sl.section_id,
  i.section_code,
  i.section_number,
  i.section_letter,
  i.section_title,
  i.printed_question_no,
  i.internal_question_no,
  i.question_sort_key,
  i.question_text,
  i.guide_to_inspection,
  i.answer_type,
  i.answer_options,
  COALESCE(i.answer_options_inferred, false),
  COALESCE(i.inspection_marker, ''),
  COALESCE(i.is_removed_question, false),
  COALESCE(i.is_active, true),
  i.guide_status,
  i.source_page_start,
  i.source_page_end,
  i.raw_source_text,
  md5(COALESCE(i.question_text, '') || '|' || COALESCE(i.guide_to_inspection, '') || '|' || COALESCE(i.raw_source_text, '')),
  COALESCE(i.metadata, '{}'::jsonb),
  auth.uid(),
  auth.uid()
FROM input_rows i
CROSS JOIN qs
JOIN section_lookup sl
  ON sl.question_set_id = qs.question_set_id
 AND sl.section_code = i.section_code
ON CONFLICT (question_set_id, internal_question_no)
DO UPDATE SET
  section_id = EXCLUDED.section_id,
  section_code = EXCLUDED.section_code,
  section_number = EXCLUDED.section_number,
  section_letter = EXCLUDED.section_letter,
  section_title = EXCLUDED.section_title,
  printed_question_no = EXCLUDED.printed_question_no,
  question_sort_key = EXCLUDED.question_sort_key,
  question_text = EXCLUDED.question_text,
  guide_to_inspection = EXCLUDED.guide_to_inspection,
  answer_type = EXCLUDED.answer_type,
  answer_options = EXCLUDED.answer_options,
  answer_options_inferred = EXCLUDED.answer_options_inferred,
  inspection_marker = EXCLUDED.inspection_marker,
  is_removed_question = EXCLUDED.is_removed_question,
  is_active = EXCLUDED.is_active,
  guide_status = EXCLUDED.guide_status,
  source_page_start = EXCLUDED.source_page_start,
  source_page_end = EXCLUDED.source_page_end,
  raw_source_text = EXCLUDED.raw_source_text,
  source_hash = EXCLUDED.source_hash,
  metadata = EXCLUDED.metadata,
  updated_by = auth.uid();

COMMIT;

SELECT
  'RISQ question chunk 11/15 imported.' AS result,
  '08F.008' AS chunk_first_question,
  '10A.002' AS chunk_last_question,
  (SELECT COUNT(*) FROM public.risq_questions q JOIN public.risq_question_sets qs ON qs.id = q.question_set_id WHERE qs.question_set_code = 'RISQ_3_2') AS total_questions_imported_so_far;
